#include <bits/stdc++.h>
using namespace std;
int main() {
    vector<int> v = {5, 2, 8, 1, 9, 3};

    // ── Ascending (default) ──
    sort(v.begin(), v.end());
    // v = {1, 2, 3, 5, 8, 9}

    // ── Descending ──
    sort(v.begin(), v.end(), greater<int>());
    // v = {9, 8, 5, 3, 2, 1}

    // ── Sort a subarray [l, r) ──
    sort(v.begin() + 1, v.begin() + 4);  // Sort indices 1,2,3 only

    // ── Sort array ──
    int a[] = {4, 2, 7, 1};
    sort(a, a + 4);

    // ── Custom comparator: sort pairs by second value descending ──
    vector<pair<int,int>> pairs = {{1,5},{2,3},{3,9},{4,1}};
    sort(pairs.begin(), pairs.end(), [](const pair<int,int>& x, const pair<int,int>& y) {
        return x.second > y.second;  // by second value, descending
    });
    // pairs = {{3,9},{1,5},{2,3},{4,1}}

    // ── Sort strings by length, then lexicographically ──
    vector<string> words = {"banana", "fig", "apple", "kiwi", "mango"};
    sort(words.begin(), words.end(), [](const string& a, const string& b) {
        if (a.size() != b.size()) return a.size() < b.size();
        return a < b;  // tie-break lexicographically
    });
    // words = {"fig", "kiwi", "apple", "mango", "banana"}
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    vector<int> v = {1, 3, 3, 3, 5, 7, 9};
    //              idx: 0  1  2  3  4  5  6

    // ── How many elements == 3? ──
    auto lo = lower_bound(v.begin(), v.end(), 3); // points to index 1
    auto hi = upper_bound(v.begin(), v.end(), 3); // points to index 4
    cout << (hi - lo) << "\n";     // 3 occurrences

    // ── Index of lower_bound ──
    cout << (lo - v.begin()) << "\n";   // 1

    // ── Largest element <= x ──
    int x = 4;
    auto it = upper_bound(v.begin(), v.end(), x);
    if (it != v.begin()) {
        --it;
        cout << *it << "\n";   // 3  (largest value <= 4)
    }

    // ── Count elements in [l, r] inclusive ──
    int l = 3, r = 7;
    auto cnt = upper_bound(v.begin(), v.end(), r) -
               lower_bound(v.begin(), v.end(), l);
    cout << cnt << "\n";   // 5  (elements 3,3,3,5,7)

    // ── Binary search the ANSWER (classic CP technique) ──
    // Is it possible to do task with parameter k?
    // find min valid k:
    int lo2 = 1, hi2 = 1e9, ans = -1;
    while (lo2 <= hi2) {
        int mid = lo2 + (hi2 - lo2) / 2;
        // if (isPossible(mid)) { ans = mid; hi2 = mid - 1; }
        // else lo2 = mid + 1;
        (void)mid;
        break;
    }
    (void)ans;
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    vector<int> v = {1, 2, 3, 4, 5};

    // ── accumulate: sum (or any fold) ──
    long long total = accumulate(v.begin(), v.end(), 0LL);  // 15
    // Note: start with 0LL not 0 to avoid int overflow!
    cout << total << "\n";   // 15

    // ── accumulate with custom op: product ──
    long long product = accumulate(v.begin(), v.end(), 1LL,
                                   [](long long acc, int x){ return acc * x; });
    cout << product << "\n";  // 120

    // ── partial_sum: builds prefix sums in-place ──
    vector<int> prefix(v.size());
    partial_sum(v.begin(), v.end(), prefix.begin());
    // prefix = {1, 3, 6, 10, 15}
    for (int x : prefix) cout << x << " ";
    cout << "\n";

    // ── iota: fill with consecutive values ──
    vector<int> idx(5);
    iota(idx.begin(), idx.end(), 0);  // idx = {0, 1, 2, 3, 4}
    // CP use: sort indices by value in v
    sort(idx.begin(), idx.end(), [&](int a, int b){ return v[a] < v[b]; });
    for (int i : idx) cout << i << " ";  // sorted indices
    cout << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    // ── Generate all permutations ──
    vector<int> v = {1, 2, 3};
    sort(v.begin(), v.end());  // MUST start sorted for complete enumeration
    do {
        for (int x : v) cout << x << " ";
        cout << "\n";
    } while (next_permutation(v.begin(), v.end()));
    // Prints all 6 permutations: 123, 132, 213, 231, 312, 321

    // ── reverse ──
    vector<int> a = {1, 2, 3, 4, 5};
    reverse(a.begin(), a.end());
    // a = {5, 4, 3, 2, 1}

    // ── rotate: bring element at mid to front ──
    vector<int> b = {1, 2, 3, 4, 5};
    rotate(b.begin(), b.begin() + 2, b.end());
    // b = {3, 4, 5, 1, 2}  (rotation left by 2)
    for (int x : b) cout << x << " ";
    cout << "\n";

    // ── unique: remove CONSECUTIVE duplicates (must sort first!) ──
    vector<int> c = {1, 3, 3, 2, 1, 1, 4};
    sort(c.begin(), c.end());            // {1, 1, 1, 2, 3, 3, 4}
    c.erase(unique(c.begin(), c.end()), c.end());
    // c = {1, 2, 3, 4}
    for (int x : c) cout << x << " ";
    cout << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    vector<int> v = {4, 7, 2, 7, 1, 9, 3};

    // ── find: returns iterator to first match ──
    auto it = find(v.begin(), v.end(), 7);
    if (it != v.end())
        cout << "Found 7 at index " << (it - v.begin()) << "\n";  // 1

    // ── count: occurrences ──
    cout << count(v.begin(), v.end(), 7) << "\n";  // 2

    // ── count_if: conditional count ──
    int evens = count_if(v.begin(), v.end(), [](int x){ return x % 2 == 0; });
    cout << evens << "\n";   // 2 (4 and 2)

    // ── min/max element ──
    auto mn = min_element(v.begin(), v.end());
    auto mx = max_element(v.begin(), v.end());
    cout << *mn << " " << *mx << "\n";   // 1 9
    cout << (mn - v.begin()) << "\n";    // index 4

    // ── fill / fill_n ──
    vector<int> a(5);
    fill(a.begin(), a.end(), -1);        // {-1,-1,-1,-1,-1}
    fill_n(a.begin(), 3, 0);             // {0,0,0,-1,-1}
    for (int x : a) cout << x << " ";
    cout << "\n";
    return 0;
}

