// Given N strings, sort them by:
// 1. Number of distinct characters (ascending)
// 2. If equal, by string length (ascending)
// 3. If still equal, lexicographically
// Print the sorted strings.

sections.solution:
#include <bits/stdc++.h>
using namespace std;

void solve() {
    int n;
    cin >> n;
    vector<string> v(n);
    for (string& s : v) cin >> s;

    auto distinct = [](const string& s) {
        return (int)set<char>(s.begin(), s.end()).size();
    };

    sort(v.begin(), v.end(), [&](const string& a, const string& b) {
        int da = distinct(a), db = distinct(b);
        if (da != db) return da < db;
        if (a.size() != b.size()) return a.size() < b.size();
        return a < b;
    });

    for (const string& s : v) cout << s << "\n";
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int t; cin >> t;
    while (t--) solve();
    return 0;
}
